import{_ as t,o as r,c as o,a3 as a}from"./chunks/framework.CjquFG0V.js";const g=JSON.parse('{"title":"3. Definitions","description":"","frontmatter":{"title":"3. Definitions","eba":"Doctors in Training 2022-2026","topics":["preliminary"]},"headers":[],"relativePath":"ebas/doctors-in-training/preliminary/3-definitions.md","filePath":"ebas/doctors-in-training/preliminary/3-definitions.md"}'),i={name:"ebas/doctors-in-training/preliminary/3-definitions.md"};function n(s,e,c,p,l,h){return r(),o("div",null,[...e[0]||(e[0]=[a('<h1 id="_3-definitions" tabindex="-1">3. Definitions <a class="header-anchor" href="#_3-definitions" aria-label="Permalink to &quot;3. Definitions&quot;">​</a></h1><p><strong>3.1</strong> In this Agreement except where the context requires otherwise:</p><p><strong>(a)</strong> Act means the Fair Work Act 2009 (Cth), as varied from time to time, and any successor to that Act.</p><p><strong>(b)</strong> Agreement means the Doctors in Training (Victorian Public Health Sector) (AMA Victoria/ASMOF) (Single Interest Employers) Enterprise Agreement 2022-2026 including all Schedules.</p><p><strong>(c)</strong> Ambassador means an appointed representative of the Association.</p><p><strong>(d)</strong> Association means the Australian Medical Association (Victoria) Limited (“AMA”) or the Australian Salaried Medical Officers Federation (Victoria Branch) (“ASMOF”).</p><p><strong>(e)</strong> CMBS means Commonwealth Medical Benefits Schedule.</p><p><strong>(f)</strong> CME means Continuing Medical Education.</p><p><strong>(g)</strong> Doctor means a registered medical practitioner employed by a Health Service as a Hospital Medical Officer, Medical Officer, Senior Medical Officer, Registrar or a person enrolled in a General Practice Training Program.</p><p><strong>(h)</strong> DH means the Department of Health, or it’s successor, however titled or styled.</p><p><strong>(i)</strong> Duty Hours means those hours for which a Doctor is rostered or paid by the Hospital.</p><p><strong>(j)</strong> Employee has the same meaning as Doctor</p><p><strong>(k)</strong> Employer has the same meaning as Health Service</p><p><strong>(l)</strong> EO Act means the Equal Opportunity Act 2010 (Vic), as amended or replaced from time to time.</p><p><strong>(m)</strong> Experience means the number of years the Doctor has been employed in a full- time, part-time or casual capacity as a Doctor or any experience as a medical practitioner in Australia or other country where the Medical Board of Australia has accepted the qualifications held for the purposes of full registration. A year of experience is 52 weeks or, if necessary to even out a roster, 53 weeks. The exceptions to this definition are as follows:</p><p><strong>(i)</strong> If the Doctor has worked a total average of 24 hours per week or less in a year, another year of employment must be completed before advancement to the next level of experience;</p><p><strong>(ii)</strong> If, for a period of 5 years or more, the Doctor has not actively practised medicine or has not been regularly employed as a Doctor over a 5 year period, any prior service and experience will not be taken into account; and</p><p><strong>(iii)</strong> Experience as a Registrar while performing Higher Duties pursuant to <a href="/eba/ebas/doctors-in-training/allowances/51-higher-duties.html">clause 51</a> (Higher Duties) will be counted as Experience for the purpose of the above where the Higher Duties period is continuous with a subsequent appointment to a Registrar position.</p><p><strong>(iv)</strong> Where a Doctor performs Higher Duties as a Registrar pursuant to <a href="/eba/ebas/doctors-in-training/allowances/51-higher-duties.html">clause 51</a> (Higher Duties) but the Higher Duties period is not continuous with a subsequent appointment to a Registrar position, the hours worked as a Registrar will contribute to the calculation of progression in accordance with subclause 3.1(m)(i) in their first year of appointment as a Registrar.</p><p><strong>(v)</strong> Where a Registrar moves from one recognised Speciality stream to another, he or she will not progress to the next higher annual incremental level for a further period of 12 months (refer subclause 3.1(bb))</p><p><strong>(vi)</strong> Where a Doctor is absent for a period of Parental Leave pursuant to subclause 67.3 (Long Parental Leave Unpaid) or 67.4 (Short Parental Leave Unpaid), the period of Parental Leave should not be considered in the calculation of the average hours worked per week in a year</p><p><strong>(n)</strong> FWC means the Fair Work Commission.</p><p><strong>(o)</strong> Health Service means a public hospital or health service listed in <a href="/eba/ebas/doctors-in-training/appendices/1-list-of-employers-health-services.html">Appendix 1</a>.</p><p><strong>(p)</strong> Health Services Act means the Health Services Act 1988 (Vic), as amended or replaced from time to time.</p><p><strong>(q)</strong> Higher Qualifications means qualifications obtained by a Doctor after graduation and includes:</p><p><strong>(i)</strong> post-graduate university degrees and diplomas for the purposes of registration as a Medical Specialist in Australia;</p><p><strong>(ii)</strong> membership or fellowship of a Specialist Medical College for the purpose of registration as a Medical Specialist in Australia;</p><p><strong>(iii)</strong> any other post-graduate qualification for the purposes of registration as a Medical Specialist in Australia;</p><p><strong>(iv)</strong> the first part or equivalent of a higher qualification as defined in this Agreement.</p><p><strong>(r)</strong> Hospital Medical Officer (“HMO”) means a Doctor with three or less years of experience and who is not performing the duties of a Medical Officer or a Registrar.</p><p><strong>(s)</strong> Hourly Rate for Hospital Medical Officers, Medical Officers and Senior Medical Officers means 1/38th of the relevant weekly rate.</p><p><strong>(t)</strong> Hourly Rate for Registrars means 1/43rd of the relevant weekly rate as the ordinary hours of work for Registrars are made up of 38 hours of ordinary duty plus 5 reasonable additional hours of training time, equalling 43 hours per week or an average of 43 hours per week for up to 4 weeks pursuant to subclause 34.</p><p><strong>(u)</strong> HSR means a health and safety representative (including a deputy health and safety representative) elected under the OHS Act.</p><p><strong>(v)</strong> Institution means any hospital, health service (whether or not listed in <a href="/eba/ebas/doctors-in-training/appendices/1-list-of-employers-health-services.html">Appendix 1</a>) or benevolent home, community health centre, Society or Association registered pursuant to the Health Services Act.</p><p><strong>(w)</strong> Medical Officer (“MO”) means a Doctor with three or more completed years of experience and who is not performing the duties of a Registrar or performing medical work covered by another Award or agreement. A Medical Officer employed solely in an administrative position and who is not eligible to be covered by any other medical Award or agreement must be paid as a Medical Officer 5th year of experience.</p><p><strong>(x)</strong> Medical Specialists Agreement means the Medical Specialists (Victorian Public Health Sector) (AMA Victoria/ASMOF) (Single Interest Employers) Enterprise Agreement 2022 – 2026.</p><p><strong>(y)</strong> NES means the National Employment Standards.</p><p><strong>(z)</strong> OHS Act means the Occupational Health and Safety Act 2004 (Vic).</p><p><strong>(aa)</strong> Parent Hospital means a Hospital that employs a Doctor, typically on a one year contract from the first week of February, on the understanding that the Doctor may be directed to work at a Rotation Hospital in order to meet the requirements of a structured training program OR to meet service demands. Separate campuses of amalgamated health services are deemed to be the one Parent Hospital.</p><p><strong>(bb)</strong> Registrar means a Doctor who is either appointed to an accredited Specialist training position (refer subclause 42.7(c)) or who holds a position designated as such by the Health Service.</p><p><strong>(cc)</strong> Regulations means the Fair Work Regulations, as varied from time to time, and any successor to those Regulations</p><p><strong>(dd)</strong> Rotation means a period during which a Doctor is directed to work at a Hospital other than the one by which they are employed (the “Rotation Hospital”), or otherwise who is engaged by more than one Health Service in a calendar year at the direction of a Specialist Medical College, as part of a structured training program or to meet service demands. The Doctor remains an employee of the Parent Hospital for the rotation period.</p><p><strong>(ee)</strong> Rotation Hospital means a hospital that receives a Doctor on rotation.</p><p><strong>(ff)</strong> Senior Medical Officer (“SMO”) means a Doctor who is employed as a Head of Department or equivalent role within the Health Service.</p><p><strong>(gg)</strong> Shiftworker, for the purposes of the NES, is any Doctor who is required to work in excess of their ordinary hours, or works ordinary hours on more than 10 weekends (defined as a Saturday or Sunday or both) during the leave accrual year.</p><p><strong>(hh)</strong> Specialist Medical College means a medical college accredited by the Australian Medical Council.</p><p><strong>(ii)</strong> Statutory Body means the Department of Health (Victoria) and, formerly the Department of Health and Human Services (Victoria) and the Department of Human Services (Victoria).</p><p><strong>(jj)</strong> A Stillborn Child is a --- child:</p><p><strong>(i)</strong> who weighs at least 400 grams at delivery or whose period of gestation was at least 20 weeks; and</p><p><strong>(ii)</strong> who has not breathed since delivery; and</p><p><strong>(iii)</strong> whose heart has not beaten since delivery.</p><p><strong>(kk)</strong> Training Time means a rostered period of time available to Registrars for five hours per week dedicated for training which is free from service calls, with the exception of calls about genuine medical emergencies or disaster situations. Forms of Training Time are set out in subclause 34.4.</p><p><strong>(ll)</strong> VHIA means the Victorian Hospitals’ Industrial Association.</p><p><strong>(mm)</strong> Week means seven consecutive days reckoned from and to midnight on Saturday night.</p><p><strong>(nn)</strong> WIRC Act means the Workplace Injury Rehabilitation and Compensation Act 2013 (Vic), or if applicable in the particular situation the Accident Compensation Act 1985 (Vic) or the Workers Compensation Act 1958 (Vic).</p><p><strong>3.2</strong> Except where the context requires otherwise, a reference in this Agreement to “Hospital”, &quot;hospital&quot; or &quot;health care facility&quot;, &quot;public health sector agency&quot; or similar term is a reference to the hospital, health care facility, public health sector agency operated by a Health Service listed in <a href="/eba/ebas/doctors-in-training/appendices/1-list-of-employers-health-services.html">Appendix 1</a> to this Agreement.</p><p><strong>3.3</strong> Where an Act of Parliament or Regulation referred to in this Agreement is or has been replaced by another Act of Parliament or Regulation, the reference to such an Act or Regulation shall be taken to refer to the successor Act or Regulation.</p><p><strong>3.4</strong> Where this Agreement refers to a condition of employment provided for in the NES, the relevant definitions in the Act apply.</p><p>Plain language terms: glossary, meanings.</p>',59)])])}const m=t(i,[["render",n]]);export{g as __pageData,m as default};
